(window.courseContentFiles = window.courseContentFiles || {})["000003/0016"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">138. Заболявания на нервната система: Мозъчен оток, повишено интракраниално налягане, вклиняване и хидроцефалия</h1><h2>Мозъчен оток</h2><p>Мозъчният оток представлява нарастване на водното съдържание в мозъчната тъкан, което води до увеличение на нейния обем.</p><h3>Етиология и морфогенеза</h3><p>Според патогенетичните механизми се различават три основни вида оток:</p><ul><li><strong>Вазогенен (екстрацелуларен):</strong> <p>Този вид оток се развива в междуклетъчното пространство. Основната причина за него е <strong>нарушената кръвно-мозъчна бариера</strong>. Най-често се наблюдава при състояния като артериална хипертония, тумори, абсцеси или интоксикация с олово. Поради увредената бариера, плазмените съставки преминават от кръвоносните съдове в мозъчната тъкан.</p></li><li><strong>Цитогенен (токсичен, интрацелуларен):</strong> <p>При него течността се натрупва вътре в самите клетки. Основният патогенетичен механизъм е <strong>нарушената работа на K/Na помпа</strong>. Това се случва най-вече при исхемия, водна интоксикация или състояния на остра хипонатриемия, което води до навлизане на вода в клетката и нейното набъбване.</p></li><li><strong>Интерстициален (перивентрикуларен):</strong> <p>Този оток е локализиран в тъканта около мозъчните стомахчета. Той е пряко свързан с наличието на <strong>хидроцефалия</strong>. Патогенезата тук включва <strong>нарушен транс-епендимен воден транспорт</strong> – поради повишеното налягане в стомахчетата, гръбначномозъчната течност се просмуква през епендимния слой в околната мозъчна паренхима.</p></li></ul><p>Често механизмите са комбинирани поради едновременно нарушение на КМБ и водно-електролитното равновесие. Отокът може да бъде дифузен или перифокален (около огнищни процеси като хеморагии или тумори).</p><h3>Макроскопски характеристики</h3><p>При дифузен оток мозъкът е с увеличено тегло и обем, гънките са сплеснати, а браздите са силно стеснени. Срезната повърхност е овлажнена и блестяща, като границата между кората и бялото вещество е замъглена. Мозъчните вентрикули изглеждат цепковидни. В напреднали стадии може да се развие оточна некроза на бялото вещество. При цитогенния оток мозъкът може да е сух, състояние известно като мозъчно набъбване.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/sP8gdcWP427Agm6LxWpcFc_eY_RzbQT0CdCbQ-a98AkuQkg2IRiTuCAb5AmFKHmYXdTajWt8lkLmS_N4qMDqKWk79vJVcukUOjSQpk-N7tRLSZHuSmk9S7xGZxGzMD0gE7TaZgqsL0iHi_bw7j1SWNm-TeKepfO1-4RlB75VMOLVSO4VmgXzZuCJbUFFH6MF?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775996860082-2\">Микроскопски характеристики</span></h3><p>Наблюдава се периваскуларно (във <span class=\"editor-note\" data-note=\"## Анатомично разположение\nТези пространства обграждат малките кръвоносни съдове, докато те преминават от повърхността на главния мозък (субарахноидалното пространство) навътре в мозъчния паренхим.\n- Граници: Пространството е разположено между външната стена на кръвоносния съд и обвивката от израстъци на астроцитите.\n- Слоеве: Те са „тапицирани“ от продължения на меките мозъчни обвивки (пиа матер). ## Съдържание и функции\nВирхов-Робеновите пространства играят критична роля за физиологията на мозъка:\n- Дренаж на интерстициална течност: Те служат като канали за изчистване на метаболитни отпадъци от мозъчната тъкан.\n- Глимфатична система: Те са основен компонент на т.нар. „глимфатична система“ (съчетание от „глия“ и „лимфа“). През тях циркулира цереброспинална течност, която „измива“ мозъка от протеини като бета-амилоид (свързан с болестта на Алцхаймер).\n- Имунологична роля: В тези пространства често се срещат макрофаги, които действат като имунна бариера и пречистват чужди частици, преди те да достигнат до паренхима. ## Клинично значение\nВ патологията състоянието на тези пространства може да бъде индикатор за различни процеси:\n- Дилатация: Когато пространствата станат видими на ЯМР е нормален белег на стареенето, но може да бъде свързано и с:\n- Хипертония.\n- Церебрална малка съдова болест.\n- Деменция.\n- Натрупвания: При определени заболявания в тези пространства могат да се натрупат възпалителни клетки (периваскуларни муфи при енцефалит) или протеини (амилоидна ангиопатия).\" id=\"note-1775997094220-3\">Вирхов-Робеновите пространства</span>) и перицелуларно просветляване. При специфични състояния, като <strong>прионни </strong>енцефалити, се развива <em><strong><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fwww.researchgate.net%2Fprofile%2FRoselene-Ecco%2Fpublication%2F6738679%2Ffigure%2Ffig1%2FAS%3A667204429312014%401536085340749%2FSpongiform-change-status-spongiosus-in-the-cerebellar-white-matter-arrow-of-a.ppm&amp;f=1&amp;nofb=1&amp;ipt=e62520679cb1d30d91b626439c0a040fd08c15cf7267588e534e4ee688bf051e &quot;width=100%&quot;)\" id=\"note-1775997169669-4\">status spongiosus</span></strong></em>, при който в мозъка се виждат множество кухини, придаващи му вид на гъба.</p><p>В резултат на отока се увеличава мозъчния обем. При нарастването му над 8% от изходния (това е обемната разлика между мозъка и черепната вместимост) се развива СПВЧН. Поради това мозъчният оток обикновено се съпровожда с мозъчна дислокация и вклиняване.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хидроцефалия</h2><p>Хидроцефалията е патологично разширение на ликворните пространства.</p><h3>Етиология и патогенеза</h3><p>Възниква поради блокаж на циркулацията или нарушен баланс между образуването и абсорбцията на цереброспиналната течност. Основните причини включват обтурация на ликворните пътища от тумори или възпаления, нарушена абсорбция или хиперпродукция на ликвор.</p><h3>Видове хидроцефалия</h3><ul><li><strong>Некомуникираща (обтурационна):</strong> Дължи се на запушване на пътищата (напр. <em>aquaeductus Sylvii</em> или отворите на Magendi и Luschka).&nbsp;Конкретните причини за появата й най-често са мозъчни тумори на 3-ти и 4-ти вентрикул, последвани по честота от хронично възпаление, абсцеси, хеморагии на малкия мозък, грануломи, паразити. Обтурационната хидроцефалия е асиметрична при запушване на foramen Monro.</li><li><strong>Комуникираща (необструктивна, абсорбционна):</strong> Свързана е с хиперпродукция (възпаление, папилом на хориоидния плексус) или нарушена абсорбция на ликвор в субарахноидното пространство (хронични менингити, субарахноидни кръвоизливи, тромбоза на венозните синуси).</li><li><strong>Хидроцефалия ex vacuo (пасивна):</strong>&nbsp;Това е вид комуникираща хидроцефалия вследствие на атрофия на мозъка. Може да е вродена, поради вътреутробни инфекции (токсоплазмоза, цитомегалия) или свързана с малформации (поренцефалия, микрогирия, вродена стеноза на акведукта) и малформативни синдроми, каквито са с-м на Dandy-Walker, с-м на Arnold-Chiari. Придобитата хидроцефалия у възрастни е свързана с мозъчна атрофия, породена от атеросклероза или дегенеративни заболявания.</li></ul><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/HZgd_pafsRYnug8vUiUFC14rLMtCtGykbQqdKNxSd3BmGOvXKVLNiD-iS0oWocX494-2ainOwQMrgAXEeeEJulMppJmrjnXW6dAX0BeRy8W4bbwXmgZlctK2N_YVH5e1jc7PiWDN2t47K0Z43D1Zqm-emq1V44SO5KKar4DM63-vjuHfwKgxjk0olmkIS5dq?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775996822911-1\">Макроскопски характеристики</span></h3><p>Вентрикулната система е разширена симетрично или асиметрично. Бялото мозъчно вещество е атрофично, а <em>corpus callosum</em> е силно изтънял. При новородени състоянието води до увеличение на черепа и не затваряне на фонтанелите.</p><h3>Изход</h3><p>Увеличение на мозъчния обем, интерстициален оток и СПВЧН.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Синдром на повишено вътречерепно налягане (СПВЧН)</h2><p>СПВЧН се дефинира като увеличение на ликворното налягане над 200 mm воден стълб или 15 mm живачен стълб. Патоморфологичен еквивалент на СПВЧН са мозъчните вклинявания или хернии.</p><h3>Етиология</h3><p>Синдромът се развива при всички патологични процеси, които водят до увеличаване на обема на черепното съдържание, включително обемни процеси като тумори, абсцеси, грануломи, хеморагии и др.</p><h3>Клинична картина</h3><p>Класическата клинична триада на СПВЧН включва:</p><ol><li>Силно главоболие.</li><li>Повръщане.</li><li><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/UUwLZysDPTZQjjrY74G_kQr2c2ep31vm9XRp-9qK-OpPkt9L3vjBfCUxt_lheiWN_OAGjIgJLWwiJoVulmn8e1WFlsm731CvQp2EnT3z5pBnXwHqo1lhdbYM-02SYkairdjNhjNnE6Y7zkQDERfWB5EresnqaG1u8LukAwfkb84oXquiVu89c6jfjziot5RZ?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775997548424-6\">Застойни папили при офталмоскопия</span>.</li></ol><h3>Макроскопски</h3><p>Вклиняванията (хернииране) са патоморфологичният еквивалент на СПВЧН и представляват пролабиране на част от мозъчната тъкан през естествени отвори на черепа или гънки на dura mater.</p><h4><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/eu_A8zF4jDZLeNs6gGF8jY3uWph5LJFLlP9YdAZxhDjlSZLdbS3v0WTprvqHnWHUB9PkOLRsZJNfecRBl55RUZBtk7ZioVJwdtEnVyDeQMHyhVWYpGV27D7sCUuFUF8zjvyYRhhYIKqVfqjO98huHd9FxpENl2bmxxl-kaN04lqiz6Faj_rm-bDXiUK5YY_W?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775997502810-5\">Видове вклинявания</span></h4><ul><li><strong>Малкомозъчно вклиняване:</strong> Тонзилите на малкия мозък се вмъкват в големия тилен отвор (<em>foramen magnum</em>), притискайки продълговатия мозък. Това е честа причина за смърт поради увреждане на дихателния център, като могат да причинят и булбарна парализа.</li><li><strong>Темпорално (субтенториално) вклиняване:</strong> Долната темпорална гънка преминава през тенториума и притиска мезенцефалона и задната мозъчна артерия. <p>При него се уврежда контралатералното </p><p>мозъчно краче с развитие на парализа на III-ия ЧМН от същата страна, инфаркт в </p><p>мозъка при силна компресия на задна мозъчна артерия, руптура на пенетриращи артерии с вторични </p><p>стволови кръвоизливи (т.нар. кръвоизливи на </p><p>Duret).</p></li><li><strong>Субфалксово (цингуларно) вклиняване:</strong> Част от <em>gyrus cinguli</em> преминава под <em>falx cerebri</em> в срещуположната половина.</li><li><strong>Горно малкомозъчно вклиняване:</strong> <p>Част от вермиса и краниалната малкомозъчна </p><p>кора пролабират през тенториума в средна черепна ямка. Развива се при обемни процеси в малкия </p><p>мозък.</p></li></ul><h3>Усложнения</h3><p>Увеличеният мозъчен обем притиска вените и/или ликворните пътища, предизвиква общомозъчна исхемия, която задълбочава мозъчния оток. Връзката между двата процеса е много тясна и двупосочна. СПВЧН се причинява често от мозъчен оток и от своя страна утежнява развитието му.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">139. Менингити и енцефалити: Видове и морфологична характеристика</h1><h1 style=\"text-align: center\">Менингити</h1><p>Менингитът представлява възпалителен процес на меките мозъчни обвивки, при който се наблюдава събиране на ексудат в субарахноидното пространство.</p><h3>Етиология</h3><p>Причинителите са изключително разнообразни:</p><ul><li><strong>Вируси:</strong>&nbsp;</li><ul><li><strong>Първични вирусни менингити:</strong>&nbsp;<p>Ентеровируси (<i>ECHO-вируси</i>, <i>Coxsackie</i> вируси), както и вирусът на лимфоцитарния хориоменингит на Армстронг.</p></li><li><p><strong>Вторични вирусни менингити:</strong> </p><p>Вируси на грип, паротит (заушка), морбили, варицела, <i>Herpes-simplex</i>, <i>Epstein-Barr</i> вирус (инфекциозна мононуклеоза).</p><br></li></ul><li><strong>Бактерии:</strong>&nbsp;</li><ul><li><strong>Новородени:</strong> Най-чест причинител е <i>Escherichia coli</i>.</li><li><strong>Деца до 3 години:</strong> Основен причинител е <i>Haemophilus influenzae</i>.</li><li><strong>Деца и юноши</strong>: Най-характерен е <i>Neisseria meningitidis</i> (Менингокок).</li><li><strong>Възрастни:</strong> Преобладават пневмококи, стрептококи и стафилококи. Те често са вторични (след отит, синузит или пневмония).</li></ul></ul><ul><li><strong>Други:</strong> Туберкулозни микобактерии, луетична спирохета и гъбички (кандидоза, криптококоза).</li></ul><h3>Морфогенеза</h3><p>Микроорганизмите достигат до ЦНС по три основни пътя:</p><ol><li><strong>Хематогенно:</strong> Най-честият път на разпространение.</li><li><strong>По съседство:</strong> От инфекции на костните синуси, средното ухо или мастоидния израстък.</li><li><strong>Директно:</strong> При черепно-мозъчни травми или медицински манипулации.</li></ol><h3>Клиника</h3><p>Менингитите се проявяват със следните основни синдроми:</p><ul><li><strong>Общ инфекциозен синдром</strong></li><li><strong>Синдром на менингеално дразнене</strong></li></ul><p>При <strong>хроничните менингити</strong> към клиничната картина се добавят:</p><ul><li><strong>Хидроцефален синдром</strong></li><li><strong>Увреждане на ЧМН-и.</strong></li></ul><h3>Диагностика</h3><p>Най-съществените промени се установяват в <strong>ликвора</strong>. Те имат решаваща диагностична стойност за определяне на:</p><ol><li>Етиологията.</li><li>Характера на възпалението.</li></ol><h3>Видове според морфологичната характеристика</h3><p>Патоморфологичните промени зависят от вида на причинителя:</p><ul><li><strong>Серозни менингити (остри лимфоцитни):</strong> Предизвикват се предимно от вируси. Дифузни се и се&nbsp; характеризират с дифузен оток, хиперемия и инфилтрация от лимфоцити и макрофаги.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/4fgpSawzrKNCL5XMF67houxerfujfIm4copFod41azaYjP1pXKnAquqQff73O1-mGGY8b4Ol3NIJ_UQkEN3Q6vhXZEYSXteONsPMyNzWbJnUY0GWlwH-UOFpTKXCifxLbR6w6TPkBCqyR8ADfvg6lkWaLgQaQ80vm6w_o7gRQSWITORz5zfJKyhNbaTBdYw6?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775998711973-7\">Гнойни менингити</span>:</strong> Причиняват се от гноеродни бактерии. Ексудатът е гноен и може да бъде разположен <strong><u>конвексиално </u></strong>(по повърхността) или базално.</li><li><strong>Грануломатозни менингити:</strong> Срещат се при туберкулоза (<strong><u>базален </u></strong>пихтиест ексудат и туберкули), луес (базални млечнобели менинги и луетични грануломи) или микози (<strong><u>базални </u></strong>съответни грануломи).</li><li><strong>Хроничен фиброзен базален менингит:</strong> Крайна фаза на неизлекувани менингити, протичаща с облитерация на <p>субарахноидното пространство </p>и формиране на кисти. Етиологията е полиетиологична.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Епидемичен цереброспинален менингит</h2><p>Това е остро инфекциозно заболяване, което се проявява със септична ангина и гнойно възпаление на менингите.</p><h3>Етиология</h3><p>Причинява се от <em>Neisseria meningitidis</em> (патогенни форми А и В). Заразяването става по въздушно-капков път от болни и заразоносители. Менингококите се развиват коменсално в устната кухина или причиняват лек назофарингит. Менингит възниква при изразена вирулентност и понижена имунна реактивност.</p><h3>Клиника:</h3><p>Известни са две клинико-морфологични форми - типична и свръхостра форма.</p><h3>Типична форма</h3><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://s3.amazonaws.com/static.wd7.us/3/33/Meningitis_1.jpg?20080424173128 &quot;width=100%&quot;)\" id=\"note-1775999147585-8\">Макроскопски</span>:</strong></li><ul><li><p>През първия ден се установява</p><p>хиперемия и кръвоизливи с обилен мътен ексудат в </p><p>субарахноидното пространство</p></li><li><p>За 1-2 ден ексудатът става гноен</p>, образува „<span class=\"editor-note\" data-note=\"![Image](https://encrypted-tbn3.gstatic.com/images?q=tbn:ANd9GcTLP19jaIiO_TGnSXdjG3YhUCiG0sR26daqjb4IIZzBZnb7nchCbQLiKSQocZwO &quot;width=100%&quot;)\" id=\"note-1775999186245-9\">гнойна шапка</span>“ по конвекситета и обхваща базалните менинги.</li><li>Мозъкът е силно оточен, а вентрикулите съдържат гной с жълтеникави налепи по епендима.</li></ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://webpath.med.utah.edu/jpeg5/CNS190.jpg &quot;width=100%&quot;)\" id=\"note-1775999221440-10\">Микроскопски</span>:</strong></li><ul><li>Преобладава масивна неутрофилна инфилтрация с макрофаги, лимфоцити и фибрин.</li><li>След 1-2 дни възпалението прониква и в мозъчната кора.</li><li><p>Менингококи могат да се докажат цитологично в ликвора.</p></li></ul><li><strong>Изход и усложнения:</strong></li><ul><li><p>Пълна резорбция на ексудата или оздравяване с фиброзиране на менингите.</p></li><li><p>Може да се </p><p>усложни с тежък мозъчен оток, със СПВЧН, с вклиняване, с разпространение на инфекцията </p>към мозъка.</li></ul></ul><h3>Свръхостра форма на менингококова инфекция (Менингококов сепсис, Синдром на Waterhouse-Friderichsen)</h3><p>Може да възникне като усложнение на типичната форма или да се прояви още в началото с фулминантен (светкавичен) ход и смъртен изход за 24 часа, преди да се манифестира менингита.</p><ul><li><strong>Клиника:</strong></li><ul><li>Остро начало с висока температура и характерни хеморагични обриви по кожата.</li><li>Бързо преминаване в шоково състояние, което е резистентно на лечение.</li></ul><li><strong>Патогенеза:</strong></li><ul><li>Предизвиква се от менингококовия ендотоксин, отделящ се при разпадането на бактериите. </li><li><p>Ендотоксинемията причинява тежка </p><p>ендотелна увреда, активираща факторите на съсирването с последващо развитие на ДИК.</p></li><li><p>Роля може да </p><p>има сензибилизацията на организма и потисната </p><p>имунна активност.</p><br></li><li>Възможна роля на дефицит в комплементната система (С6-С9).</li></ul><li><strong>Макроскопски:</strong></li><ul><li>Многобройни кръвоизливи по кожата, лигавиците и серозните обвивки.</li><li>Хеморагично-некротични промени във вътрешните органи.</li><li><p>Фибриноидна некроза и/или </p><p>фибринови тромби в съдовете на микроциркулацията - капиляри, артериоли, венули.</p><br></li><li><strong></strong><p>Типична находка </p><p>са !<strong><span class=\"editor-note\" data-note=\"![Image](https://upload.medbullets.com/topic/109018/images/waterfried.jpg &quot;width=100%&quot;)\" id=\"note-1775999249296-11\">двустранните масивни кръвоизливи в надбъбреците!</span></strong>.</p></li><li><p>В менингите има оток, хиперемия и единични сегментоядрени левкоцити.</p></li></ul><li><strong>Изход:</strong></li><ul><li>Обикновено фатален, вследствие на рефрактерен септичен шок и остра надбъбречна недостатъчност.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Пневмококови менингити</h2><ul><li>Срещат се главно у възрастни вследствие на хематогенно пренасяне на инфекцията от вътрешни органи, най-често белите дробове. </li><li>Ексудатът е богат на неутрофилни левкоцити и фибрин.</li><li>В менингите се образуват плътни сраствания при организацията на ексудата.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Стрептококови и стафилококови менингити</h2><ul><li>Те са резултат от септикопиемия или разпространение на инфекцията от гноен синузит, отит, тромбофлебит на дурални венозни синуси. </li><li>Усложненията са идентични на тези при епидемичния менингит, но има по-голяма възможност от образуване на мозъчен инфаркт или кръвоизлив, поради честото въвличане на съдовете във възпалителния процес.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Грануломатозни менингити</h2><p>Те възникват при <span class=\"editor-note\" data-note=\"![Image](https://www.researchgate.net/publication/329408066/figure/fig1/AS:700314307026944@1543979350896/Gross-pathology-of-brain-Thick-gelatinous-subarachnoid-exudate-that-fills-the-basal.ppm &quot;width=60%&quot;)\" id=\"note-1775999357749-12\">туберкулоза</span>, луес, микотични инфекции (коксиоидоза, криптококоза, кандидоза, аспергилоза) и други.</p><h3>Клиника</h3><p>Характерни за клиничното протичанеса:</p><ul><li>Синдром на менингеално дразнене</li><li>Хидроцефално-хипертензионен синдром</li><li>Увреждане на ЧМН, поради базалната локализация на патологичния процес.</li><li>Образуване на мозъчни инфаркти при туберкулоза и особено при луес във връзка с облитериращия ендартерит.</li><li>Промени в ликвора, съответстващи на причинителя</li></ul><h3>Патоморфология. </h3><p>За разлика от гнойния менингит, тук ексудатът е концентриран предимно по <strong>базалната повърхност </strong>на мозъка. Той има желатинозен или зърнист вид (поради специфичните грануломи).</p>Носи белезите на съответните основни болестни процеси./вж. Инфекциозна патология/<h2>Хроничен обострен фиброзен базален менингит (базален кистичен арахноидит)</h2><p>Това е крайна фаза на неизлекувани менингити с различна етиология, фиброзирането на менингите причинява или пълна облитерация на субарахноидното пространство или частични сраствания с формиране на кисти.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Енцефалити</h1><p>Енцефалитите са възпалителни процеси в мозъчното вещество, които се делят на:</p><ul><li><strong>Фокални некротично-гнойни:</strong> причинени от бактерии или микози.</li><li><strong>Дифузни алтернативно-възпалителни:</strong> причинени от вируси, рикетсии и неконвенционални агенти.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Бактериални инфекции на мозъка</h2><p>Гнойното възпаление в мозъчното вещество протича под формата на мозъчен абсцес или дифузен емболичен гноен енцефалит (церебрит). Тези процеси могат да бъдат първични или да се развият като усложнение на гноен менингит.</p><h3>Мозъчен абсцес</h3><p><strong>Определение\n</strong>Огнищно гнойно-некротично възпаление, ограничено от глиална и фиброзна капсула. </p><p><strong>Етиология\n</strong>Причинява се най-често от стрептококи, пневмококи, стафилококи, клебсиела, произлизащи от гнойни огнища в белите дробове, ушите, синусите, мастоидния израстък, носа, кожата на лицето или при бактериален ендокардит. </p><p><strong>Клиника</strong>\nКлинично се характеризира със съчетание на СПВЧН с огнищна неврологична симптоматика. Възможно е да липсват прояви на инфекциозно заболяване. Ликворът е с повишено клетъчно и белтъчно съдържимо.</p><p><strong>Патоморфология</strong></p><ul><li><strong>Начален стадий:</strong> Локален пиогенен енцефалит (церебрит). Наблюдава се ограничена некроза с левкоцитна инфилтрация (гной) без демаркация. Тъканта е размекната, жълтеникава и с кръвоизливи.</li><li><strong>Стадий на формиране на пиогенна мембрана (14-21 ден):</strong> Гнойният ексудат се обгражда от капсула от гранулационна тъкан. Поради нарушена КМБ и пропускливи новообразувани съдове се развива тежък перифокален оток, водещ до асиметрично вклиняване.</li><li><strong>Стадий на фиброзиране на капсулата (2-3 месеца):</strong> Капсулата се състои от фибробластна и астроглиална тъкан (глиофиброза). Тя е по-плътна към менингите, докато пробивът на гнойта обикновено става във вентрикулната система през по-нежната част на капсулата.</li></ul><p><strong>Усложнения\n</strong>Pyocephalus internus (гной в мозъчните стомахчета), перифокален оток, вклиняване и пробив в субарахноидното пространство, водещ до менингит.</p><h3>Дифузен бактериален гноен енцефалит (церебрит)</h3><p>Развива се обикновено при септикопиемия.</p><ul><li><strong>Макроскопски:</strong> Не дава характерна картина, освен общи белези на мозъчен оток.</li><li><strong>Микроскопски:</strong> В кората и в бялото вещество се откриват множество периваскуларни инфилтрати, богати на левкоцити, със зони на микроабсцедиране и кръвоизливи.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остри вирусни енцефалити и миелити</h2><p>Тези възпалителни процеси се причиняват от вируси, които притежават специфичен тропизъм към нервната система или към нейни конкретни анатомични структури. В зависимост от локализацията и обема на засягане, заболяванията се класифицират на:</p><ul><li><strong>Полиоенцефалити:</strong> Възпалителните процеси са локализирани основно в сивото мозъчно вещество (<p>напр. бяс, остър полиомиелит)</p>.</li><li><strong>Левкоенцефалити:</strong> Патологичните промени са ограничени в бялото мозъчно вещество.</li><li><strong>Паненцефалити:</strong> Характеризират се с дифузно засягане на мозъка, без селективна локализация в сивото или бялото вещество.&nbsp;<p>Към тази група спадат редица заболявания, предавани чрез вектори като комари или кърлежи, които се характеризират и с специфично географско разпространение.</p></li></ul><h4>Етиология и патогенеза</h4><p>Голяма група от ДНК и РНК вируси проявяват невротропизъм към определени топографски структури. Вирусите проникват в ЦНС по няколко начина:</p><ul><li><strong>Хематогенно:</strong> Чрез виремия.</li><li><strong>Периневрално:</strong> Ретроградно по хода на лимфните пътища или чрез невроаксоналния ток.</li></ul><p>Когато възпалителният процес обхване целия спектър на нервната система, включително нервните коренчета и периферните нерви, състоянието се дефинира като енцефаломиелополирадикулоневрит.</p><h4>Морфологична картина</h4><p>Въпреки разликите в етиологията, вирусните енцефалити споделят сходна хистологична картина, различавайки се предимно по топографията на лезиите:</p><ul><li><strong>Макроскопски:</strong> Промените са неспецифични и включват оток и конгестия на мозъка и менингите. Съществуват изключения, като грипния енцефалит, който протича с изразени кръвоизливи, и Herpes-simplex енцефалитът, характеризиращ се с фокални некротични лезии.</li><li><strong>Микроскопски:</strong> Налице е характерна хистологична триада:</li><ol><li><strong>Клетъчна алтерация:</strong>&nbsp;</li><ul><li><i>Неспецифични промени</i>: цитопатогенен ефект, водещ до клетъчен оток, хроматолиза и клетъчна смърт, което провокира невронофагия (фагоцитоза от микроглия и макрофаги).</li><li><i>Специфични промени</i>:&nbsp;<p>Дължат се на директна вирусна репликация, като появата на ядрени или цитоплазмени инклузионни телца. Според класификацията на Coudry биват: </p></li><ul><li><p><strong>Тип А:</strong> Еозинофилни, единични, хомогенни, със светло хало.</p></li><li><p><strong>Тип В:</strong> По-малки от тип А, мултиплени, без наличие на хало.</p><br></li></ul></ul><li><strong>Мононуклеарни инфилтрати:</strong> Лимфоцити и макрофаги с типично периваскуларно разположение.</li><li><strong>Глиални възли (нодули):</strong> Резултат от огнищна пролиферация на глията.</li></ol></ul><h3>Остър преден полиомиелит (Poliomyelitis anterior acuta)</h3><p><strong>Синоними:</strong> Детски паралич, Болест на Heine-Medin.</p><h4>Етиология и патогенеза</h4><ul><li><strong>Причинител:</strong> Полиовируси (тип I, II и III), семейство <em>Picornaviridae</em>. Най-патогенен е тип I (<strong>Брунхилда</strong>).</li><li><strong>Механизъм:</strong> Заразяването е ентерално. Вирусът се репликира в лигавицата на червата и фаринкса, преминава в кръвта (<strong>виремия</strong>) и поразява избирателно <strong>мотоневроните на предните рога</strong> на гръбначния мозък (особено шийното и поясното задебеление).&nbsp;<p>Може да засегне и двигателните ядра на мозъчния ствол, чак до гигантските пирамидни клетки на Бец в прецентралната мозъчна кора.</p></li></ul><h4><strong></strong></h4><h4>Клиника:</h4><p>Клиничната картина се определя от локализацията на вирусната репликация в нервната система и етапът на възпалителния процес.</p><ol><li><strong>Спинална форма:</strong> Най-честата изява. Характеризира се с развитие на вяла пареза или парализа на долни или горни крайници вследствие на увреждането на мотоневроните в предните рога на гръбначния мозък.</li><li><strong>Булбарна, понтинна и енцефална форма:</strong> Тези варианти протичат значително по-тежко поради засягане на жизненоважни структури в мозъчния ствол.</li></ol><p>Заболяването преминава през четири фази, всяка от които има специфичен патоморфологичен израз:</p><ul><li>Предпаралитичен стадий.</li><li>Паралитичен (остър) стадий.</li><li>Възстановителен (подостър) стадий.</li><li>Резидуален (хроничен) стадий.</li></ul><h4>Морфологични стадии и промени</h4><ul><li><strong>Остра фаза:</strong></li><ul><li><strong>Макроскопски:</strong> <p>Мозъкът е оточен и хиперемиран. На срез границата между сиво и бяло вещество е заличена, Н-образната фигура е неясна, виждат се точковидни кръвоизливи.</p></li><li><strong>Микроскопски:</strong>&nbsp;Тежки алтеративни промени в мотоневроните: <strong>хроматолиза </strong>(разпадане на нилсовото вещество), клетъчен оток и некроза. Засегнатите неврони се обграждат от микроглия и макрофаги, оформящи <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-12/text-editor-images/2026/04/1776013728660-image.png &quot;width=100%&quot;)\" id=\"note-1776013256993-13\">невронофагични възелчета</span></strong>. Установяват се също <strong>полиморфна възпалителна инфилтрация </strong>(неутрофили, лимфоцити) и <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-12/text-editor-images/2026/04/1776013721425-image.png &quot;width=100%&quot;)\" id=\"note-1776013271608-14\">еозинофилни инклузии</span> </strong>(тип В по Coudry). Често се засягат и менингите.</li></ul><li><strong>Подостра фаза:</strong></li><ul><li><strong>Макроскопски:&nbsp;</strong><p>Засегнатите огнища придобиват сивкаво-ръждив цвят поради хемосидерина от миналите кръвоизливи.</p></li><li><strong>Микроскопски:</strong>&nbsp;<p>Острият ексудат намалява. Доминира устойчива <strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/syxlKcSzQz6BmogNZTpBwaAP2TTTh4OUGR7lVEl5UQC26ZIhjrWyoRpHe7m-fz6z3PZmsBygSl30t5mFPHmmbj9IhFp2A2b0I9jPNCKcG6MHXqb49xJVPenerYiQloBydeJbxD4pBnOlpQ0_MfxfLzpbFDgvhL9OedbcAGNdSifyiBrf2BElExt0VLMd5CTC?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1776013300231-15\">лимфоцитна перивазална инфилтрация</span></strong> (т.нар. лимфоцитни „маншони“ около съдовете), която може да персистира дълго време.</p></li></ul><li><strong>Хронична фаза (Резидуална):</strong></li><ul><li><strong>Макроскопски:</strong> Предните рога на гръбначния мозък са отчетливо <strong>атрофични</strong>, бледи и осеяни с <strong>микрокисти </strong>(остатъци от некротични зони). Наблюдава се видима атрофия на предните коренчета.</li><li><strong>Микроскопски:</strong> Пълна загуба на мотоневрони, последвана от немасивна <strong>глиофиброза </strong>(заместване на нервната тъкан с глия). Мускулите, инервирани от тези сегменти, показват тежка <strong>денервационна атрофия</strong>.</li></ul></ul><h4>Клинични изходи</h4><p>Заболяването може да прогресира до респираторна недостатъчност (поради парализа на диафрагмата и междуребрените мускули) или възходяща парализа на Ландри. Булбарните форми са особено тежки, с висока смъртност (до 75%) поради парализа на жизненоважни центрове. При преживелите остават трайни парези, парализи и деформации, дължащи се на денервационната мускулна атрофия. Чести причини за късна смърт са вторични инфекции като пневмония и уросепсис.</p><h3>2. Полиомиелитоподобни енцефалити</h3><p>Заболявания, които клинично, епидемиологично и морфологично не се различават съществено от детския паралич. </p><ul><li><strong>Етиология:</strong> Предизвикват се от ентеровируси от групата <em>Picornaviridae</em> (ECHO, Coxsackie A и B, ентеровируси 70 и 71), а понякога и от <em>Herpes simplex</em>.</li><li><strong>Диагностика:</strong> Разграничаването от класическия полиомиелит се извършва единствено чрез лабораторна вирусна идентификация.</li></ul><h3>3. Бяс (Rabies)</h3><p>Остър, нелечим полиоенцефаломиелит, причинен от РНК вирус от семейство <em>Rhabdoviridae</em>.</p><ul><li><strong>Епидемиология и морфогенеза:</strong> Предава се чрез слюнка при ухапване от заразени животни (кучета, вълци, лисици, рядко прилепи). Вирусът се репродуцира в мускулите, достига до сензорните ганглии и се разпространява в ЦНС. Инкубационният период е 15-20 дни.</li><li><strong>Клиника:</strong> Започва с главоболие и температура, преминавайки в сетивна свръхвъзбудимост, хидрофобия, фотофобия и конвулсии.</li><li><strong>Микроскопска картина:</strong></li><ul><li><strong>Дегенеративни промени:</strong> Най-силно изразени в пода на IV вентрикул, стените на III вентрикул, мезенцефалона, базалните ганглии и хипокампа.</li><li><strong>Невронофагични възли:</strong> Описвани като „възелчета на бяса“.</li><li><strong>Патогномонични находки:</strong> <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-12/text-editor-images/2026/04/1776013710409-image.png &quot;width=100%&quot;)\" id=\"note-1776013324759-16\">Телца на Babes-Negri</span></strong> – цитоплазмени включвания (<u>мултиплени, с еозинофилен център и базофилна периферия</u>), разположени в невроните на хипокампа и клетките на Purkinje в малкия мозък.</li></ul><li><strong>Електронномикроскопски данни:</strong> Центърът на телцата на Negri съдържа вирусни протеини, заобиколени от нуклеокапсиди.</li><li><strong>Изход:</strong> Заболяването е фатално, като смъртта настъпва вследствие на булбарна парализа. Единствената ефективна мярка е профилактиката чрез противобясна ваксина.</li></ul><h3>4. Енцефалити от арборвируси</h3><p>Група трансмисивни енцефалити с подчертано географско разпространение, пренасяни от членестоноги.</p><ul><li><strong>Етиология:</strong> Вируси от семейство <em>Togaviridae </em>с изявен тропизъм към ЦНС.</li><li><strong>Епидемиология:</strong> Резервоар са гръбначни животни, а преносители — кърлежи и комари. В България и съседните страни спорадично се среща Далекоизточният руски енцефалит.</li><li><strong>Микроскопска картина:</strong> Картина на <strong>паненцефалит</strong>. Наблюдават се типични белези на вирусна инфекция: огнищни и изолирани невронални некрози, дегенерация и лимфоцитна инфилтрация.</li><li><strong>Диагноза:</strong> Базира се на вирусологични изследвания, съобразени с епидемиологичната обстановка и специфичния географски ареал.</li></ul><h3>5. Herpes-simplex virus (HSV) енцефалит</h3><p>Това е латентна вирусна инфекция, която обикновено протича безсимптомно, но при определени условия може да предизвика тежък енцефалит. Различават се два основни варианта: <strong>HSV-I (лабиален)</strong> и <strong>HSV-II (генитален)</strong>.</p><h4>HSV-I енцефалит</h4><p>Засяга всички възрасти, като рискът е повишен при деца, младежи и имунокомпрометирани пациенти. При около 10% от заболелите се установява анамнеза за предшестващ лабиален херпес.</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-12/text-editor-images/2026/04/1776013698887-image.png &quot;width=100%&quot;)\" id=\"note-1776013465876-17\">Макроскопска картина</span>:</strong> Установяват се <strong>хеморагично-некротични</strong> <strong>промени </strong>с характерна локализация в <strong>темпоро-базалните и фронто-базалните части</strong> на мозъка. Понякога се засяга и мозъчният ствол.</li><li><strong>Микроскопска картина:</strong> Налице е дифузна, обилна полиморфно-клетъчна възпалителна инфилтрация. Диагностично специфични са <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-12/text-editor-images/2026/04/1776013686647-image.png &quot;width=100%&quot;)\" id=\"note-1776013478436-18\">интрануклеарните включвания тип А по Coudry</span></strong>, които се откриват в невроните и глиалните клетки.</li><li><strong>Диагностика:</strong></li><ul><li>Култивиране на вируса от ликвор (най-точен метод).</li><li>Доказване на вирусен антиген в мозъчна биопсия чрез имунопероксидазна техника.</li><li><em>In situ</em> хибридизация (високочувствителен метод).</li></ul><li><strong>Други прояви:</strong> HSV-I може да предизвика още серозен менигит, вакуолерна миелопатия (увреждане на латералните и дорзалните стълбове) или субакутен енцефалит със засягане на бялото мозъчно вещество.</li></ul><h4>HSV-II енцефалит</h4><p>Този вариант предизвиква паненцефалит, който морфологично наподобява HSV-I инфекцията, но се проявява предимно при новородени на фона на генерализирана вирусна инфекция.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Бавно развиващи се вирусни енцефалити</h3><p>Характеризират се с дълъг латентен период, бавен прогресиращ ход и липса на класическите клинични и епидемиологични белези на острите инфекциозни заболявания.</p><ul><li><strong>Основни представители:</strong></li><ul><li>Субакутен склерозиращ паненцефалит (ССПЕ).</li><li>Прогресивна мултифокална левкоенцефалопатия (ПМЛ).</li><li>Рубеолна енцефалопатия.</li></ul></ul><p><em>Забележка:</em> Прионните болести (спонгиоформени енцефалопатии), които доскоро се класифицираха тук, вече се разглеждат в раздела за дегенеративни заболявания на нервната система.</p><h4>Субакутен склерозиращ паненцефалит (ССПЕ)</h4><ul><li><strong>Етиология:</strong> Морбилозен РНК вирус (сем. <em>Paramyxoviridae</em>).</li><li><strong>Морфогенеза:</strong> Вирусът персистира в мозъка без активна репликация поради дефект на М-протеина (белтък от вътрешната обвивка, отговорен за сглобяването и отделянето на вирусните частици от клетката).</li><li><strong>Клинична картина:</strong> Проявява се с разнообразни хиперкинезии и дълбоки личностни промени.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-12/text-editor-images/2026/04/1776013676821-image.png &quot;width=100%&quot;)\" id=\"note-1776013595886-19\">Макроскопска картина</span>:</strong> Бялото мозъчно вещество е сиво-белезникаво, губи своя блясък и хомогенност.</li><li><strong>Микроскопска картина:</strong></li><ul><li>Полета на несистемна демиелинизация, некроза и псевдокисти в бялото вещество.</li><li>Наличие на нодуларна и дифузна глиоза.</li><li>Възпалителната реакция е слабо изразена, представена от перивазални мононуклеарни клетки.</li><li><strong>Диагностичен белег:</strong> В началните фази се откриват <strong>интрануклеарни включвания тип А по Coudry</strong> в невроните и глиалните клетки.</li></ul><li><strong>Диагноза:</strong> Поставя се чрез мозъчна биопсия, съчетана с имуноморфологично доказване на вирусни частици чрез специфични антитела.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">140. Трансмисивни и спонгиоморфни енцефалопатии - прионови заболявания</h1><h2>Определение и обща характеристика</h2><p>Прионовите болести, известни още като спонгиоформени енцефалопатии от неконвенционални агенти, представляват група заболявания, обединени от наличието на еднотипна спонгиоформена дегенерация на сивото мозъчно вещество. Дълго време те са причислявани към бавно-вирусните инфекции поради доказания им трансмисионен начин на предаване. Впоследствие обаче е установено натрупване на специфичен амилоид (PrPd), което ги сродява с дегенеративни заболявания като болестта на Алцхаймер.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология и патогенеза</h2><p>Причинителите на тези заболявания са приони – протеинни инфекциозни частички с ниско молекулно тегло и малки размери, които не съдържат нуклеинови киселини (ДНК или РНК). Прионите се отличават с изключителна резистентност към стандартни методи на дезинфекция като формалин, ултравиолетови лъчи, радиация и висока температура.</p><p>Патогенезата включва превръщането на нормалния клетъчен прионов протеин (PrPc), който е разтворим, в патологична форма (PrPd) с бета-конфигурация. Този патологичен протеин полимеризира в амилоидни фибрили, наречени скрепи-асоциирани филаменти (S.A.F.). Трансмисионният характер на заболяванията е доказан чрез инокулиране на филтрат от мозък на болно животно в мозъка на здрави екземпляри, при които след дълъг латентен период (около 18 месеца) се развива идентична симптоматика.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патоморфология</h2><h3>Макроскопски характеристики</h3><p>Макроскопските промени често са неспецифични. При болестта на Якоб-Кройцфелд може да се наблюдава мозъчна атрофия в крайните стадии. При Куру макроскопски промени обикновено не се откриват.</p><h3>Микроскопски характеристики</h3><p>Основният морфологичен белег е <strong>status spongiosus</strong> (гъбест вид). Той включва:</p><ul><li><strong>Тежка вакуолизация:</strong> Сливане на цитоплазмени вакуоли в невропила и невроните на сивото мозъчно вещество, което придава порьозен, микрокистичен вид на тъканта.</li><li><strong>Алтерация на невроните:</strong> Наблюдава се силна редукция до пълна загуба на неврони.</li><li><strong>Глиоза:</strong> Астроглиална пролиферация, съпътстваща невроналната загуба.</li><li><strong>Липса на възпаление:</strong> Характерно за прионовите болести е пълното отсъствие на възпалителна реакция.</li><li><strong>Амилоидни плаки:</strong> В някои случаи (особено при Куру) се откриват специфични плаки с амилоидно ядро.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинични форми при хората</h2><h3>Болест на Jacob-Creutzfeldt (Якоб-Кройцфелд)</h3><p>Това е най-честата прионова болест при хората, наричана още трансмисивна деменция.</p><ul><li><strong>Честота:</strong> Развива се спорадично, най-често при мъже в петото десетилетие от живота.</li><li><strong>Клинична картина:</strong> Проявява се с прогресираща деменция и тежки неврологични нарушения.</li><li><p><strong>Микроскопски:</strong> </p><p>Наблюдава се <strong>тежка вакуолизация </strong>на невропила и невроните в сивото вещество, която придава характерен гъбест (<strong>status spongiosus</strong>), микрокистичен вид на тъканта. \nУстановява се <strong>астроглиална пролиферация</strong>, съчетана със значителна редукция до загуба на неврони. <strong>Възпалителна реакция липсва</strong>. Рядко в малкия мозък могат да се открият плаки „куру“.</p></li><li><p><strong>Електронномикроскопски</strong>: </p><p>В перикариона и израстъците на невроните се наблюдават големи мембранно-ограничени вакуоли, в част от които се откриват S.A.F.</p></li><li><p><strong>Диагноза</strong>: </p><p>Основава се на електронномикроскопската находка. Имунооцветяване с антисерум срещу прионния протеин се използва за доказване на неговите изоформи и за откриване на плаки „куру“.</p></li></ul><h3>Куру</h3><p>Заболяване, локализирано сред племето Форе в Нова Гвинея.</p><ul><li><strong>Етиология:</strong> Свързва се с ритуален канибализъм (консумация на мозъци на починали родственици), практикуван предимно от жени и деца.</li><li><strong>Клинична картина:</strong> Протича с церебеларна атаксия и тремор, прогресиращи до пълно обездвижване.</li><li><strong>Микроскопски:&nbsp;</strong>Наличие на <strong>спонгиоформена дегенерация </strong>и характерни „<strong>плаки куру</strong>“ – струпвания от амилоиден протеин в сивото вещество.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">141. Демиелинизиращи заболявания. Мултиплена склероза</h1><h2>Обща характеристика</h2><p>Демиелинизиращите заболявания са група патологични състояния, обединени от водещия процес на демиелинизация (разрушаване на миелиновите обвивки при запазени аксони). Те обикновено са свързани с имунно-медирана патогенеза и възникват вследствие на инфекциозни или други неуточнени етиологични фактори. Типичен и най-често срещан представител на тази група е мултиплената склероза.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Мултиплена склероза</h2><p>Мултиплената склероза е хронично неврологично заболяване с рецидивиращ и прогресиращ ход, чиято основна морфологична характеристика е наличието на широко разпространени демиелинизационни огнища, известни като <strong>глиосклеротични плаки</strong>.</p><h3>Етиология</h3><p>Етиологията на заболяването не е напълно изяснена. </p><p>Обсъжда се вирусната етиология, евентуално от вируса на кучешката чума (който е близък до морбилозния), режим на хранене, инток сикация с тежки метали. Имуногенетични проучвания разкриват асоциация с определени HLA антигени.</p><h3>Патогенеза</h3><p>Патогенезата е имунно-медирана и включва взаимодействие между генетични фактори и външната среда. Наблюдава се дисбаланс в клетъчно-медирания имунитет с <strong>инхибиране на Т-супресорите и активиране на Т-хелперите по време на криза</strong>. Морфологичен субстрат на имунния процес е <strong>масивната Т-лимфоцитна инфилтрация в плаките</strong> с преобладаване на Т-хелперите. Специфична находка е рязкото увеличение на ликворните имуноглобулини (олигоклонални ивици), което се счита за вторичен феномен.</p><h3>Клинична картина</h3><p>Клиничните прояви са разнообразни и зависят от локализацията на плаките. Характерна е класическата <strong>триада на Charcot</strong>, която включва <strong>нистагъм</strong>, <strong>интенционен тремор </strong>и <strong>дизартия</strong>. Заболяването засяга предимно жени в активна възраст (между 20 и 40 години) и води до трайна инвалидизация. Ликворното изследване показа персистиращо увеличение на <strong>олигоклонални имуноглобулини</strong>, които нормално липсват или са в минимални количества.</p><h3>Макроскопски характеристики</h3><p>Патоморфологичната картина е патогномонична за диагнозата. Наблюдават се ясно ограничени плаки на демиелинизация с различна форма и големина.</p><ul><li><strong>Локализация:</strong> Плаките се разполагат в бялото вещество на главния мозък (често симетрично), мозъчния ствол, перивентрикулрано, малкомозъчните крачета, гръбначния мозък, зрителните нерви и chiasma opticum. Характерна е перивентрикуларната локализация, особено в <strong>зоната на Steinert</strong> (ъгъла между <em>n. caudatus</em> и <em>corpus callosum</em>).</li><li><strong>Видове плаки:</strong> Свежите плаки са бледорозови и меки, докато хроничните са сивкави, рязко ограничени и с жилава (гумоподобна) консистенция.</li></ul><h3>Микроскопски характеристики</h3><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-12/text-editor-images/2026/04/1776023088200-image.png &quot;width=100%&quot;)\" id=\"note-1776023090149-20\">Активни (свежи) плаки</span>:</strong> Наблюдава се оток, демиелинизация и интензивен възпалителен процес с лимфоцитна инфилтрация. Установява се пролиферация на микроглия и макрофаги, които фагоцитират миелиновите фрагменти.</li><li><strong>Хронични (неактивни) плаки:</strong> Характеризират се с остър ръб, изразена глиофиброза (пролиферация на астроглия), наличие на хипертрофични астроцити и слаба лимфоцитна инфилтрация.</li><li><strong>Плаки-сенки:</strong> Зони на частична загуба на миелин, които постепенно преливат в нормалното бяло вещество.</li></ul><h3>Диагноза</h3><p>Диагнозата се подпомага от специфични оцветявания за миелин и за аксони. Имунохистохимично в центъра на плаките преобладават В-лимфоцити, а в периферията – Т-хелпери, чието увеличение корелира с прогресията на процеса.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остър демиелинизиращ енцефаломиелит</h2><p>Това е полиетиологично възпалително заболяване, засягащо предимно бялото мозъчно вещество.</p><h3>Етиология и патогенеза</h3><p>Развива се като усложнение след общи инфекции (морбили, рубеола, заушка, варицела, Epstein-Barr вирус) или след ваксинации (например срещу бяс). Патогенезата е имунно-медирана, като възпалението се състои от клетки, участващи в имунния отговор.</p><h3>Морфология</h3><p>Микроскопски се установява дисеминиран възпалителен процес с перивенозна локализация на лимфо-плазмоцитни инфилтрати. Промените са най-силно изразени на границата между сивото и бялото мозъчно вещество. При тежки случаи може да се развие хеморагичен енцефалит с петехиални кръвоизливи.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">142. Дегенеративни заболявания на централната нервна система. Болест на Алцхаймер</h1><h2>Обща характеристика и класификация</h2><p>Дегенеративните заболявания на нервната система са голяма група заболявания с голямо медицинско и социално значение. Основният им клиничен симптом е деменцията – прогресивно снижаване на интелектуалните способности на пациента. Съвременната класификация на тези състояния се базира на доказването на патологични протеини в мозъчната тъкан, като бета-амилоид, тау-протеин, убиквитин, алфа-синуклеини и патологичен прионов протеин. Към тази група, освен болестта на Алцхаймер и Паркинсон, се причисляват деменцията с телца на Леви, болестта на Пик и прионовите болести.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Болест на Алцхаймер</h2><p>Заболяването се характеризира с корова дегенерация и тежка прогресираща деменция. Наблюдава се значително нарастване на честотата му в цивилизованите страни, което се обяснява с удължаването на продължителността на живота.</p><h3>Макроскопски характеристики</h3><p>Наблюдава се дифузна, симетрична <strong>церебрална атрофия</strong>, която е най-силно изразена в:</p><ul><li><strong>Челните (фронтални) и теменните (париетални) дялове.</strong></li><li><strong>Хипокампалната формация</strong> (критично за паметта).</li></ul><h3>Микроскопски характеристики</h3><p>Основните патоморфологични промени са два вида:</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://pathology.or.jp/corepicturesEN/17/c04/images/03.jpg &quot;width=100%&quot;)\n**Микроскопски находки** (оцветяване по Bodian и имунооцветяване за β-амилоиден протеин):\nУстановяват се три сенилни плаки с различна големина, които са имунохистохимично позитивни за β-амилоиден протеин. При сребърното оцветяване се виждат вълнообразни фибрили под формата на невропилни нишки.\" id=\"note-1776086701726-0\">Невритни (сенилни) плаки</span>:</strong>&nbsp;Това са <strong>извънклетъчни </strong>струпвания от дегенерирали невритни израстъци около <strong>ядро от β-амилоид</strong>. /<i>Доказват се с Конгорот или Тиофлавин S.</i>/</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://www.news-medical.net/image-handler/ts/20200125035213/ri/673/picture/2020/1/1-16.jpg &quot;width=100%&quot;)\" id=\"note-1776086800507-1\">Неврофибрилни възли</span>:</strong>&nbsp;Това представлява&nbsp;<strong>вътреклетъчен</strong> хиперфосфорилиран <strong>тау-протеин</strong>, организиран в <p>двойни усукани хеликси. </p>/<i>Доказва се със сребърна импрегназция</i>/.</li></ul><p>За диагнозата на болеста на Алцхаймер освен наличието на посочените два типа промени е съществена и локализацията и гъстотата на неврофибрилните възли в различни отдели на ЦНС, което определя и стадирането на заболяването в 6 степени.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Болест на Паркинсон (Идиопатичен паркинсонизъм)</h2><p>Това е дегенеративно заболяване, което засяга стрио-палидо-нигралната система. Клинично се проявява с класическа триада: <strong>дребен статичен тремор</strong>, <strong>брадикинезия </strong>и <strong>повишен мускулен тонус</strong>. Болестта трябва да се различава от паркинсоновия синдром, който може да бъде симптом на атеросклероза или интоксикации.</p><h3>Макроскопски характеристики</h3><p>Наблюдава се характерно избледняване на <em>substantia nigra</em> и на <em>locus coeruleus</em> в мезенцефалона.</p><h3>Микроскопски характеристики</h3><p>Установява се прогресивно <strong>разрушаване на пигментираните (меланин-съдържащи) неврони</strong>.</p><p>Патогономичен белег за болестта са: <strong></strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-13/text-editor-images/2026/04/1776087283959-image.png &quot;width=100%&quot;)\" id=\"note-1776087259767-2\"><strong>Т</strong><strong>елцата на Леви</strong></span><strong></strong> – окръглени цитоплазмени включвания с по-бледа централна част и ясно очертана периферия. Могат да са повече от едно, локализирани в цитолазмата на невроните или лежащи свободно сред невропила. Доказват се имунохистохимично с антитела срещу <strong>убиквитин </strong>и <strong><span class=\"editor-note\" data-note=\"![Image](https://www.ous-research.no/toft/docs/Bilder/Lewy_Body_alphaSynuclein.jpg &quot;width=40%&quot;)\" id=\"note-1776087309979-3\">алфа-синуклеин</span></strong>, при което посочените протеини се експресират силно в периферията им.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Латерална амиотрофична склероза</h2><p>Системно дегенеративно заболяване на мотоневроните. Клинично протича с парализи, които прогресивно се засилват и водят до фатален край в рамките на 3 до 5 години.</p><h3>Етиология и патогенеза</h3><p>Етиологията не е напълно изяснена, като се предполага действието на токсични фактори (има доказана връзка с хранителен токсин). За разлика от други дегенеративни болести, тук не са доказани отлагания на специфични протеини.</p><h3>Морфологична характеристика</h3><p>Макроскопски промени обикновено не се долавят. Микроскопски се откриват тежки неспецифични дегенеративни изменения и некроза на мотоневроните от мозъчната кора до предните рога на гръбначния мозък. Наблюдава се загуба на неврони, минимална глиална реакция и пълна липса на възпаление.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">143. Тумори на централната нервна система. Класификация</h1><h2>Обща характеристика на мозъчните тумори</h2><h4><strong>1. Произход и класификация</strong></h4><p>Процесите в черепната кутия се разделят на три основни групи:</p><ul><li><strong>Първични тумори:</strong> Произхождат от специфичните клетки на НС (невроепителни), обвивките (менингеоми) или мезенхимни, лимфопоетични и ембрионални структури.</li><li><strong>Метастатични тумори:</strong> Изключително често срещани (над <strong>30%</strong> от случаите в последните години).</li><li><strong>Врастващи тумори:</strong> Процеси от съседни структури (орбита, синуси, кости на черепа), които ангажират мозъка вторично.</li></ul><h4><strong>2. Ключови биологични особености</strong></h4><p>В невропатологията съществува сериозно <strong>несъответствие между хистологична картина и клинично поведение</strong>:</p><ul><li><strong>Биологична злокачественост:</strong> Всеки мозъчен тумор е потенциално фатален, тъй като повишава вътречерепното налягане (<strong>СПВЧН</strong>) в затвореното пространство на черепа.</li><li><strong>Локализация:</strong> Тумор, който е хистологично „доброкачествен“, може да бъде биологично „злокачествен“, ако е разположен в жизненоважни центрове (напр. мозъчен ствол).</li><li><strong>Инфилтративен растеж:</strong> При глиомите инвазията в околната тъкан е правило, независимо от степента на диференциация на клетките.</li><li><strong>Липса на типични метастази:</strong> Дори най-агресивните форми (<strong>Глиобластом</strong>) рядко дават метастази извън ЦНС, тъй като <strong>в мозъка няма лимфни пътища</strong>.</li></ul><h4><strong>3. Възрастова и топографска зависимост</strong></h4><ul><li><strong>Детска възраст:</strong> Преобладават малигнени <strong>ембрионални тумори</strong> (една от водещите причини за смъртност при децата).</li><li><strong>Възрастни (50–70 г.):</strong> Доминират малигнените <strong>глиални тумори</strong> (глиоми).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Класификация на невроепителните тумори</h2><p>Това е най-голямата и специфична за ЦНС група тумори. Според класификацията на СЗО те се разделят на няколко основни вида:</p><ol><li>Астроцитни тумори (най-многобройни).</li><li>Олигодендроглиални тумори.</li><li>Олигоастроцитни (смесени) тумори.</li><li>Епендимни тумори.</li><li>Тумори на плексус хориоидеус.</li><li>Невронални и смесени невроглиални тумори.</li><li>Тумори в пинеалната област.</li><li>Ембрионални тумори.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Астроцитни тумори</h2><p>Те съставляват 60% от глиомите и 30% от всички тумори на ЦНС. Разделят се на 4 степени (I–IV) според степента на анаплазия.</p><h4><strong>Общи критерии за степенуване (WHO):</strong></h4><ul><li>Повишена <strong>клетъчна плътност</strong> (целуларност).</li><li><strong>Митотична активност</strong> и пролиферативен индекс (Ki-67).</li><li>Наличие на <strong>неоваскуларизация</strong>.</li><li>Наличие на <strong>некрози</strong>.</li></ul><h4><strong>I степен: Високо диференцирани (Доброкачествени)</strong></h4><ul><li><strong>Примери:</strong> Пилоцитен астроцитом, Субепендимен гигантоклетъчен астроцитом.</li><li><strong>Характеристика:</strong> Срещат се предимно у <strong>деца</strong>, имат бавен растеж и ограничена анаплазия.</li></ul><h4><strong>II степен: Дифузен астроцитом</strong></h4><ul><li><strong>Локализация:</strong> Най-честият при възрастни; типично в бялото мозъчно вещество.</li><li><strong>Макроскопски:</strong> Трудно се отличава от нормален мозък; по-мек (ако има кисти) или плътен.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/Diffuse_astrocytoma_HE_stain.jpg/960px-Diffuse_astrocytoma_HE_stain.jpg?_=20151022062207 &quot;width=100%&quot;)\" id=\"note-1776102903346-4\">Микроскопски</span>:</strong> Равномерни клетки, слаб клетъчен атипизъм, бедна съдова мрежа. <strong>Няма некрози и кръвоизливи.</strong></li><li><strong>Прогноза:</strong> Склонност към малигнена прогресия след години.</li></ul><h4><strong>III степен: Анапластичен астроцитом</strong></h4><ul><li><strong>Микроскопски:</strong> Повишена клетъчна плътност, изразен морфологичен атипизъм, засилена съдова пролиферация и микронекрози.</li></ul><h4><strong>IV степен: Глиобластом (Glioblastoma multiforme)</strong></h4><p>Най-злокачественият първичен тумор при възрастни (пик 50–60 г.).</p><ul><li><strong>Типове:</strong> </li><ul><li><strong>De novo</strong> (първичен) – развива се бързо.</li></ul><ul><li><strong>Вторичен</strong> – чрез анаплазия от нискостепенен астроцитом.</li></ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://neuropathologyatlas.wustl.edu/cache/NEOPLASMS%20%28GLIAL%29/Glioblastoma%20-%20Gross%20Pathology/2A1%20GBM%20%28Case%202%29%208_595.jpg?cached=1696479060 &quot;width=100%&quot;)\" id=\"note-1776102974912-5\">Макроскопски</span>:</strong> Пъстра повърхност (<strong>некрози, кръвоизливи, кисти с желеподобно съдържимо</strong>). <p>Има типична локализация в centrum ovale с </p>често рапространение през <em>corpus callosum</em> към другата хемисфера (тип <strong>\"Пеперуда\"</strong>).</li><li><strong>Микроскопски (Ключова триада):</strong></li><ol><li><strong><span class=\"editor-note\" data-note=\"## Гигантоклетъчен глиобластом\n![Image](https://neuropathology-web.org/chapter7/images7/7-GCgbm.png &quot;width=78%&quot;)\n## Малкоклетъчен глиобластом\n![Image](https://neuropathology-web.org/chapter7/images7/7-scgbm.png &quot;width=67%&quot;)\" id=\"note-1776103212202-0\">Клетъчен полиморфизъм</span>:</strong> От малки клетки с хиперхромни ядра до гигантски многоядрени форми.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://neuropathology-web.org/chapter7/images7/7-13l.jpg &quot;width=100%&quot;)\" id=\"note-1776103054513-7\">Гломерулоидна неоваскуларизация</span>:</strong> Съдови пакети, приличащи на бъбречни гломерули.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://neuropathology-web.org/chapter7/images7/7-gbm-palisade.png &quot;width=100%&quot;)\" id=\"note-1776103140693-8\">Географски некрози</span>:</strong> Обширни полета от некротизирала тъкан, заградени от подредени в редици туморни клетки (<strong><span class=\"editor-note\" data-note=\"![Image](https://www.tau.ac.il/medicine/tau-only/webpath/jpeg5/cns139.jpg &quot;width=100%&quot;)\" id=\"note-1776103039752-6\">псевдопалисади</span></strong>).</li></ol></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Олигодендроглиални тумори</h2><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://neuropathology-web.org/chapter7/images7/7-oligoclear.png &quot;width=70%&quot;)\" id=\"note-1776103408859-1\">Олигодендроглиом</span> (II ст.):</strong> Произхожда от олигодендроцитите. Типично засяга бялото вещество.</li><ul><li><strong>Микроскопски:</strong> Клетките са сравнително еднакви, кръгли, с хиперхромни ядра и „<strong>светъл ореол</strong>“ (дворче). Оформят структури тип <strong>„пчелна пита“</strong> или <strong>„кафез за пилета“</strong> (<em>chicken wire</em>). <p>Стромата е от капилярен тип съдо</p><p>ве, които често кървят. </p><p>Чести <strong><span class=\"editor-note\" data-note=\"![Image](https://neuropathology-web.org/chapter7/images7/7-oligoCa.png &quot;width=100%&quot;)\" id=\"note-1776103426161-2\">калцификати</span></strong>, видими и на рентген.</p></li></ul><li><strong>Олигодендроглиом (III ст.):</strong> Повишена клетъчна плътност (целуларност), полиморфизъм, усилена съдова пролиферация и поява на некрози.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Епендимни тумори и Плексус-папиломи</h2><ul><li><strong>Епендимом (II ст.):</strong> Произхожда от епендимната глия.</li><ul><li><strong>Макроскопски:</strong> Добре ограничени възли, свързани със стените на вентрикулите; често растат в лумена им.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://neuropathology-web.org/chapter7/images7/7-16b.jpg &quot;width=100%&quot;)\" id=\"note-1776103482702-4\">Микроскопски</span>: </strong><p>Проявява се с няколко варианта. </p><p>Най-чест е клетъчният вариант, при който се наблюдават характерните <strong><span class=\"editor-note\" data-note=\"![Image](https://neuropathology-web.org/chapter7/images7/7-ependros.png &quot;width=70%&quot;)\" id=\"note-1776103473913-3\">периваскуларни епендимни розети</span></strong>. Те се състоят от туморни клетки, подредени около кръвоносните съдове във формата на \"corona radiata\". Между клетките и съда остава светла, безядрена еозинофилна зона, изпълнена с клетъчни израстъци и глиофибрили.</p></li></ul><li><strong>Плексус-папиломи:</strong> Произлизат от епитела на <em>plexus chorioideus</em>.</li><ul><li><strong>Локализация:</strong> Най-често в <strong>IV вентрикул</strong>.</li><li><strong>Клиника:</strong> Предизвикват хидроцефалия (хиперсекреторна или обтурационна).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://neurochirurgie.insel.ch/fileadmin/Erkrankungen/Hirntumor/Plexustumor/Plexuspapillom-im-Ventrikel-fr.jpg &quot;width=100%&quot;)\" id=\"note-1776103541390-5\">Структура</span>:</strong> Дървовидно разклонени <span class=\"editor-note\" data-note=\"![Image](https://neurochirurgie.insel.ch/fileadmin/Erkrankungen/Hirntumor/Plexustumor/Histopathologische-Mikroskopaufnahme-eines-Plexustumors.jpg &quot;width=100%&quot;)\" id=\"note-1776103553322-6\">папили</span>. Имат доброкачествено протичане и рядко рецидивират.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Ембрионални тумори</h2><h3><strong>Медулобластом</strong></h3><p>Най-честият ембрионален тумор в детска възраст (предимно при момчета).</p><ul><li><strong>Локализация:</strong> Vermis и малкомозъчни хемисфери; често изпълва IV вентрикул.</li><li><strong>Макроскопски:</strong> Бледорозова, мека до къслива маса с некрози и хеморагии.</li><ul><li><strong>Дезмопластичен вариант:</strong> По-плътна, \"хрущялна\" консистенция (в хемисферите).</li></ul><li><strong>Микроскопски:</strong></li><ul><li>Клетките са еднообразни, кръгли или източени (<strong>\"морковоподобни\"</strong>).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://www.wikidoc.org/images/b/bc/Medulloblastoma_with_rosettes.jpg?20151006182753 &quot;width=100%&quot;)\" id=\"note-1776103623014-7\">Псевдорозети на Hommer-Wright</span> (в 30%):</strong> Клетки, подредени в кръг около еозинофилен център с неврофибрили.</li></ul><li><strong>Биологично поведение:</strong> Инфилтративен растеж и типични <strong>ликворни метастази</strong> (в главния и гръбначния мозък).</li></ul><h3><strong>ПНЕТ (Примитивни невроектодермални тумори на ЦНС)</strong></h3><ul><li><strong>Характеристика:</strong> Хетерогенна група от ембрионални недиференцирани тумори.</li><li><strong>Разлика от Медулобластома:</strong> Разположени са <strong>супратенториално</strong> (над малкия мозък) или в гръбначния мозък.</li><li><strong>Диференциална диагноза:</strong> Трябва да се различават от периферните ПНЕТ (групата на саркома на Юинг).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3><strong>Прогноза</strong></h3><p>Прогнозата при малигнените процеси (анапластични глиоми, глиобластоми, медулобластоми) се подобрява чрез:</p><ul><li><strong>Комбинирано лечение:</strong> Лъчелечение и химиотерапия.</li><li><strong>Таргетна терапия:</strong> Прицелно въздействие върху рецептори и сигнални молекули, контролиращи растежа, инвазията и ангиогенезата.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Менингеални тумори (Менингиоми)</h2><p>Произлизат от менингоцитите (арахноидните клетки) на мозъчните обвивки. Това са предимно доброкачествени, бавно растящи тумори, които по-често засягат жените. Преобладават доброкачествените тумори, които са излечими след радикалното им хирургично отстраняване.</p><ul><li><strong>Макроскопски:</strong> Представляват плътни, добре ограничени сферични или овални възли. Обикновено са прикрепени към <strong>dura mater</strong> и не инфилтрират мозъчния паренхим, а само го притискат.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-13/text-editor-images/2026/04/1776103732672-image.png &quot;width=100%&quot;)\" id=\"note-1776103710347-8\">Микроскопски характеристики</span>:</strong></li><ul><li><strong>Менинготелни луковици:</strong> Специфична формация от спираловидно наслоени туморни клетки около централен канал или съд. Тази \"луковидна\" структура има огромна диагностична стойност.</li><li><strong>Псамомни телца:</strong> Представляват калцифицирани менинготелни луковици. Те са концентрични, слоести калциеви отлагания, оцветени базофилно (тъмносиньо). При наличие на много псамомни телца вариантът се нарича <strong>псамоматозен менингиом</strong>.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Метастатични тумори в мозъка</h2><p>Броят им нараства значително, съставлявайки над <strong>30%</strong> от всички интракраниални формации.</p><ul><li><strong>Пътища на разпространение:</strong> Почти винаги метастазирането е <strong>хематогенно</strong>. </li><li><strong>Форми:</strong> Могат да бъдат солитарни (единични) или множествени.</li><li><strong>Клинична значимост:</strong> В 1/3 от случаите мозъчната симптоматика изпреварва откриването на първичния тумор.</li><li><strong>Основни източници (по честота):</strong></li><ol><li><strong>Бял дроб</strong> (най-чест).</li><li>Млечна жлеза (гърда).</li><li>Бъбреци.</li><li>Меланом.</li><li>Стомашно-чревен тракт.</li></ol></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">144. Тумори на периферната нервна система<br></h1><h2>Неврином (Шваном / Schwannoma)</h2><p>Това е най-честият доброкачествен тумор на периферните нерви, който произхожда от Швановите клетки на обвивката. Характерното за него е, че нервът обикновено остава извън капсулата на тумора, което позволява хирургичното му отстраняване без дефицит.</p><ul><li><strong>Локализация и макроскопия:</strong> Среща се често при черепно-мозъчните нерви (типично <strong>n. statoacusticus</strong> в понтоцеребеларния ъгъл) и дорзалните коренчета на гръбначния мозък. Представлява плътен, овоиден възел с ясно изразена капсула. Срезната повърхност е сиво-жълтеникава, като често се наблюдават участъци от стари кръвоизливи и кистозни дегенерации.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-13/text-editor-images/2026/04/1776103870447-image.png &quot;width=100%&quot;)\" id=\"note-1776103872609-10\">Микроскопска картина:</span></strong> Туморът е бифазен, изграден от два типа тъкан:</li><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-13/text-editor-images/2026/04/1776103906253-image.png &quot;width=100%&quot;)\" id=\"note-1776103807830-9\">Антони А (Antoni A)</span>:</strong> <strong>Хиперцелуларни </strong>зони със снопчесто разположени клетки. Тук се наблюдават <strong>палисади</strong> (успоредно подредени ядра) и специфичните <strong>телца на Верокай (Verocay)</strong> – две успоредни редици от ядра, заграждащи светла, безядрена зона от клетъчни израстъци.</li><li><strong>Антони В (Antoni B):</strong> <strong>Хипоцелуларни</strong>, миксоидни зони с рехава структура, звездовидни клетки и микрокисти. Често се срещат дегенеративни ядрени атипизми и хиалинизирани съдове.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Малигнен тумор на обвивките на периферните нерви (MPNST)</h3><p>Високостепенен злокачествен тумор, който се развива обикновено от големите нервни стволове и е свързан анатомично с тях.</p><ul><li><strong>Хистогенеза:</strong> Произхожда от Швановите клетки или периневралните фибробласти. Тъй като тези клетки могат да произвеждат колаген при туморна трансформация, те наподобяват фибросарком.</li><li><strong>Морфология:</strong> Макроскопски е инвазивен, неясно ограничен тумор, растящ по хода на големите нервни стволове. Микроскопски се характеризира с висока клетъчна плътност, множество неправилни митози и зони на некроза. Прогнозата е неблагоприятна поради склонност към локални рецидиви и хематогенни метастази.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Тумори на симпатиковата нервна система</h2><p>Тези новообразувания произхождат от примордиалните клетки на <strong>невралния гребен</strong>. В хода на ембриогенезата тези клетки формират симпатиковите ганглии, медулата на надбъбречната жлеза и парааорталните структури.</p><h3>Невробластом</h3><p>Невробластомът е един от най-агресивните злокачествени тумори в детска възраст (обикновено до 4 години). Характеризира се с бърз растеж и ранно хематогенно метастазиране.</p><ul><li><strong>Клинична значимост:</strong> Проявява секреторна активност, като произвежда <strong>катехоламини</strong> и невронспецифична енолаза (NSE), които служат като ключови диагностични маркери. Уникално за него е способността му за спонтанна регресия или матурация.</li><li><strong>Локализация:</strong> Най-често се развива в надбъбречната жлеза и ретроперитонеалното пространство (64%), следвано от задния медиастинум (23%).</li><li><strong>Макроскопия:</strong> Туморът е мековат, розово-сивкав до червеникав, поради обилни кръвоизливи. Липсва ясна капсула и границите му често са неясни.</li></ul><h3><span class=\"editor-note\" data-note=\"## (a) Недиференциран невробластом, (b) Нискодиференциран невробластом, (c) Диференциращ се невробластом, (d) Ганглионеврома, (e) Ганглионевробластом\n![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-13/text-editor-images/2026/04/1776104301747-image.png &quot;width=100%&quot;)\" id=\"note-1776104309456-13\">Микроскопска характеристика на невробластома</span></h3><p>Морфологията варира драстично според степента на диференциация:</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-13/text-editor-images/2026/04/1776104046466-image.png &quot;width=100%&quot;)\" id=\"note-1776104049293-12\">Недиференциран вариант (беден на строма)</span>:</strong> Състои се от малки, <strong>кръгли</strong>, \"<strong>синьо</strong>-<strong>клетъчни</strong>\" <strong>невробласти </strong>с хиперхромни ядра и оскъдна цитоплазма. Липсва фибрилен матрикс. Налага широка диференциална диагноза с лимфоми и други солидни дребноклетъчни тумори при децата.</li><li><strong>Диференциран вариант:</strong> Наблюдават се белези на невронална матурация в част от клетките (5-50%). Ядрата стават по-светли с видими нуклеоли, а цитоплазмата става по-обилна и еозинофилна (незрели ганглийни клетки) или базофилна с <strong>Нислови гранулации</strong> (зрели ганглийни клетки).</li><li><strong>Специфични структури:</strong> Характерно е образуването на <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-13/text-editor-images/2026/04/1776104007820-image.png &quot;width=100%&quot;)\" id=\"note-1776104009483-11\">псевдорозети тип Homer-Wright</span></strong> – струпвания от клетки в кръг около фибрилен център (невропил), съставен от клетъчни израстъци.</li></ul><h3>Ганглионевробластом и Ганглионеврома</h3><p>Тези тумори представляват по-напреднали етапи на клетъчно съзряване:</p><ul><li><strong>Ганглионевробластом (богат на строма):</strong> Характеризира се с висок процент (над 50%) зрели ганглийни клетки. Стромата е добре развита и често съдържа Шванови клетки.</li><li><strong>Ганглионеврома:</strong> Напълно диференциран, доброкачествен тумор. Състои се от зрели ганглийни клетки, нервни влакна и сателитни клетки, организирани в Шванова строма.</li></ul><h3>Еволюция и прогноза</h3><p>Прогнозата при невробластните тумори е комплексна и зависи от няколко фактора:</p><ol><li><strong>Биологични белези:</strong> Високият митотично-кариоректичен индекс е неблагоприятен знак.</li><li><strong>Генетичен профил:</strong> Доказването на амплификация на онкопротеина <strong>N-myc</strong> е индикатор за изключително агресивно поведение и лош изход.</li><li><strong>Метастазиране:</strong> Разпространението е както лимфогенно, така и хематогенно (често в черен дроб, кости и бял дроб).</li><li><strong>Терапевтичен отговор:</strong> Съвременното лечение не само потиска тумора, но може и да индуцира неговото \"съзряване\" към по-доброкачествени форми.</li></ol><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><h2><strong></strong></h2>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
